#include <iostream>
#include <algorithm>
#include <cmath>

using namespace std;

int main() {
    int n, m, r, k;
    cin >> n >> m >> r >> k;

    int r1 = n - r + 1;
    int r2 = m - r + 1;
    int r3 = r1 * r2;

    double ans = 0.0;
    for (int i = 0; i < r1; i++) {
        for (int j = 0; j < r2; j++) {
            double temp = 1.0 * k / r3;
            temp = min(temp, 1.0 * (r1 - i) * (r2 - j) / r3);
            ans += temp;
        }
    }

    printf("%.10lf\n", ans);

    return 0;
}
